import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function EditLead() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [lead, setLead] = useState(null);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await api.get(`/leads/${id}`);
        setLead(res.data);
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load lead");
        navigate("/leads");
      }
    };

    load();
  }, [id, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setLead((prev) => ({ ...prev, [name]: value }));
  };

  const update = async (e) => {
    e.preventDefault();
    setSaving(true);

    try {
      await api.put(`/leads/${id}`, {
        name: lead.name,
        contact_number: lead.contact_number,
        email: lead.email,
        lead_source: lead.lead_source,
        status: lead.status,
        interest_level: lead.interest_level,
      });

      alert("Lead updated");
      navigate("/leads");
    } catch (err) {
      // your backend sometimes sends { errors: [...] }
      const msg =
        err.response?.data?.message ||
        (err.response?.data?.errors ? err.response.data.errors.join(", ") : null) ||
        "Update failed";
      alert(msg);
    } finally {
      setSaving(false);
    }
  };

  if (!lead) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Lead</div>
          <div className="pageSub">Update customer lead details</div>
        </div>
      </div>
      <div className="card cardPad" style={{ maxWidth: 480, margin: "32px auto" }}>
        <form onSubmit={update}>
          <label className="label">Name</label>
          <input
            className="input"
            name="name"
            value={lead.name || ""}
            onChange={handleChange}
            required
          />

          <label className="label">Contact Number</label>
          <input
            className="input"
            name="contact_number"
            value={lead.contact_number || ""}
            onChange={handleChange}
          />

          <label className="label">Email</label>
          <input
            className="input"
            name="email"
            type="email"
            value={lead.email || ""}
            onChange={handleChange}
          />

          <label className="label">Lead Source</label>
          <select
            className="select"
            name="lead_source"
            value={lead.lead_source || ""}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Source</option>
            <option value="website">Website</option>
            <option value="phone">Phone</option>
            <option value="walk-in">Walk-in</option>
            <option value="referral">Referral</option>
            <option value="other">Other</option>
          </select>

          <label className="label">Interest Level</label>
          <select
            className="select"
            name="interest_level"
            value={lead.interest_level || ""}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Interest</option>
            <option value="high">High</option>
            <option value="medium">Medium</option>
            <option value="low">Low</option>
          </select>

          <label className="label">Status</label>
          <select
            className="select"
            name="status"
            value={lead.status || ""}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Status</option>
            <option value="new">New</option>
            <option value="contacted">Contacted</option>
            <option value="converted">Converted</option>
            <option value="lost">Lost</option>
          </select>

          <button type="submit" className="btn btnPrimary" style={{ width: "100%", marginTop: 8 }} disabled={saving}>
            {saving ? "Saving..." : "Update Lead"}
          </button>
        </form>
      </div>
    </div>
  );
}
